#include <stdio.h>
#include <stdint.h>

const long long MOD = 998244353LL;

long long modpow(long long a, long long e) {
    long long r = 1;
    a %= MOD;
    while (e) {
        if (e & 1) r = (r * a) % MOD;
        a = (a * a) % MOD;
        e >>= 1;
    }
    return r;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long A, B;
        scanf("%lld %lld", &A, &B);
        long long N = A + B;
        long long chefTurns = (N + 1) / 2; // ceil(N/2)
        long long num = (A % MOD) * (chefTurns % MOD) % MOD;
        long long den = N % MOD;
        long long ans = num * modpow(den, MOD - 2) % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

