#!/usr/bin/env python3
import sys
MOD = 998244353

def mod_pow(a, e):
    return pow(a, e, MOD)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it))
        N = A + B
        chef_turns = (N + 1) // 2  # ceil(N/2)
        num = (A % MOD) * (chef_turns % MOD) % MOD
        den = N % MOD
        ans = num * mod_pow(den, MOD - 2) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

